def encode(s):
    """Encode a string into run-length encoding (list of (char, count) tuples)."""
    if not s:
        return []

    result = []
    current_char = s[0]
    count = 1

    for i in range(1, len(s)):
        if s[i] == current_char:
            count += 1
        else:
            result.append((current_char, count))
            current_char = s[i]
            count = 1

    # Don't forget the last group
    result.append((current_char, count))
    return result

def decode(pairs):
    """Decode run-length encoding back into the original string."""
    result = []
    for char, count in pairs:
        result.append(char * count)
    return "".join(result)

