        """Add a word to the trie"""
        node = self.root
        for char in word:
            if char not in node.children:
                node.children[char] = TrieNode()
            node = node.children[char]
        node.is_end_of_word = True

    def search(self, word):
        """Check if a word exists in the trie (exact match)"""
        node = self._find_node(word)
        return node is not None and node.is_end_of_word

    def starts_with(self, prefix):
        """Return all words with the given prefix, sorted"""
        node = self._find_node(prefix)
        if node is None:
            return []

        words = []
        self._dfs(prefix, node, words)
        return sorted(words)

    def _find_node(self, prefix):
        """Find the node corresponding to a prefix"""
        node = self.root
        for char in prefix:
            if char not in node.children:
                return None
            node = node.children[char]
        return node

    def _dfs(self, current_word, node, words):
        """Collect all words from a given node using DFS"""
        if node.is_end_of_word:
            words.append(current_word)

        for char, child_node in node.children.items():
            self._dfs(current_word + char, child_node, words)

