    m, n = len(s1), len(s2)

    # Create DP table where dp[i][j] = length of LCS of s1[0:i] and s2[0:j]
    dp = [[0] * (n + 1) for _ in range(m + 1)]

    # Fill the DP table
    for i in range(1, m + 1):
        for j in range(1, n + 1):
            if s1[i - 1] == s2[j - 1]:
                # Characters match, extend the LCS
                dp[i][j] = dp[i - 1][j - 1] + 1
            else:
                # Characters don't match, take the maximum from removing one char
                dp[i][j] = max(dp[i - 1][j], dp[i][j - 1])

    # Backtrack to construct the LCS string
    result = []
    i, j = m, n
    while i > 0 and j > 0:
        if s1[i - 1] == s2[j - 1]:
            # Characters match, add to result and move diagonally
            result.append(s1[i - 1])
            i -= 1
            j -= 1
        elif dp[i - 1][j] > dp[i][j - 1]:
            # LCS came from above (removing from s1)
            i -= 1
        else:
            # LCS came from left (removing from s2)
            j -= 1

    # Reverse the result since we built it backwards
    return ''.join(reversed(result))

